def fib(n: int) -> int:
    # Dictionary to store already computed Fibonacci numbers (memoization table)
    memo = {}

    def fib_recursive(k: int) -> int:
        """
        Recursive helper function that computes the nth Fibonacci number with memoization.
        """
        # Base cases
        if k == 0:
            return 0
        if k == 1:
            return 1

        # Check if the result is already in the memo
        if k in memo:
            return memo[k]

